export function getNorthCarolinaWeightLossClinicsByCity(citySlug: string): WeightLossClinic[] {
  return northCarolinaWeightLossClinics.filter(c => c.citySlug === citySlug);
}

export function getNorthCarolinaWeightLossCitiesWithClinics(): { city: string; citySlug: string; count: number }[] {
  const map = new Map<string, { city: string; citySlug: string; count: number }>();
  for (const c of northCarolinaWeightLossClinics) {
    const e = map.get(c.citySlug) || { city: c.city, citySlug: c.citySlug, count: 0 };
    e.count++; map.set(c.citySlug, e);
  }
  return Array.from(map.values());
}
